                    run_id=run_id,
                    page_no=pages[fed_idx].page_no,
                    conv_res=conv_res,
                ),
                timeout=0.0,  # non-blocking try-put
            )
            if ok:
                fed_idx += 1
                if fed_idx == total_pages:
                    ctx.first_stage.input_queue.close()
                    input_queue_closed = True
            else:  # queue full - switch to draining
